INSERT INTO zpaas_lowcode_revise.be_flow_node (id,name,`type`,description,status,node_class,cfg_requirement,tenant_id,system_id,create_time,update_time) VALUES
	 ('1','32-数据库存取','S','通支持过ORM的方式在关系型数据库中获取、插入、更改数据，输入一个对象，输出执行结果','1','cn.zpaas.lowcode.be.engine.flow.node.ORMRepositoryNode','{"节点配置参数":{"isListType":"领域对象是否是列表类型，true、false","domainObjectSource":"领域对象的获取来源，可选值包括：D、O、I、N","domainObjectKey":"源对象实例的获取关键字，参见业务逻辑流程节点中数据获取方式说明","domainObjectId":"领域对象标识","ormId":"ORM标识","repositoryOperation":"数据库操作，可选值包括：I（插入操作）、BI（批量插入操作）、DK（按主键删除操作）、UK（按主键更新操作（带空值））、UKS（按主键更新操作（不带空值））、QK（按主键查询操作）、DC（按条件删除操作）、QC（按条件查询操作）、S（保存操作）","pageFlag":"是否支持分页，true、false，当数据库操作为：QC（按条件查询操作）时有效","queryOptions":" 查询选项，当数据库操作为：QC（按条件查询操作）时有效，用于支持模糊查询、范围查询、多值查询以及比较查询,如{''fuzzyQuery'':''attr1,attr2'',''rangeQuery'':''attr3'',''multiValueQuery'':''attr4,attr5,attr6'',''attr7'':''>'',''attr8'':''<='',''orderBy'':''order by column9 desc''}"}}',NULL,NULL,NULL,NULL),
	 ('10','15-返回节点','C','中断流程并返回值，输出需要返回的值','1','cn.zpaas.lowcode.be.engine.flow.node.ReturnNode','{"节点配置参数":{"returnObjectInstanceSource":"返回对象获取来源，可选值包括：I、P、D、N、F、O，不可空","returnObjectInstanceKey":"返回对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","returnObjectInstanceAttr":"返回对象获取属性，业务逻辑流程节点中数据获取方式说明，可空"}}',NULL,NULL,NULL,NULL),
	 ('11','22-REST方法调用','I','通过HTTP REST的方式调用远程方法，输出方法执行后的返回结果','1','cn.zpaas.lowcode.be.engine.flow.node.RestInvokeNode','{"节点配置参数":{"httpMethod":"调用Rest方法的httpMethod，不可空","url":"调用Rest方法的URL，不可空","connectTimeout":"httpClient的connectTimeout参数，单位为秒","readTimeout":"httpClient的readTimeout参数，单位为秒","writeTimeout":"httpClient的writeTimeout参数，单位为秒","inParamInstanceSource":"参数实例的获取来源，可选值包括：I、P、N","inParamInstanceKey":"参数实例的获取关键字，参见业务逻辑流程节点中数据获取方式说明","isUriParam":"是否Uri参数，true、false","headerSource":"header参数的获取来源，可选值包括：I、P、N","headerKey":"header参数的获取关键字，参见业务逻辑流程节点中数据获取方式说明","ignoreCertVerify":"是否忽略HTTPS证书校验，true、false","resultKey":"包含返回结果数据的Key，为空则表示整个body都是返回结果数据"}}',NULL,NULL,NULL,NULL),
	 ('12','21-Java方法调用','I','调用原生的Java方法，输出方法执行后的返回结果','1','cn.zpaas.lowcode.be.engine.flow.node.NativeJavaInvokeNode','{"节点配置参数":{"targetJavaClass":"调用目标Java类，全package路径类名；","targetJavaMethod":"调用目标方法名","targetObjectSource":"调用目标对象来源，可选值包括：N（新建）、C（来自Spring容器）","targetMethodParamTypes":[{"paramType":"参数类型，全package路径类名","paramName":"参数名，该参数名用来在入参中获取对象，可空，为空时使用反射获取到的参数名","isList":"是否列表，true、false，可空，默认为false","elementType":"可空，当isList为true是有效，表示列表中元素的类型，如果已经指定泛型，可以不配置"}],"paramObjectSOURCE":"参数对象的获取来源，可选值包括：I、P、N","paramObjectKey":"参数对象的获取关键字，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('13','05-SpringEL表达式','B','支持执行SpringEL表达式，输出执行的结果','1','cn.zpaas.lowcode.be.engine.flow.node.SpringELNode','{"节点配置参数":{"springExpr":"SpringEL表达式，如(${1}+${2})*(${3}-${4}+${5})，其中的数字表示values列表中的顺序号，每个数字都会替换成一个值。","values":[{"valueType":"值类型，包括O（原值）、C（数组的大小）、L（字符串长度）","valueObjectSource":"值对象的获取来源，可选值包括：P、D、I、N、O、F","valueObjectIsList":"值对象是否是列表，true、false；","valueObjectKey":"值对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","valueAttrPath":"值对象属性对应的json path","contextKey":" 上下文key，当为空时，表示将值按数字替换表达式中的占位符，如${1},${2};当不为空时，表示将值以上下文Key设置到EvaluationContext中，表达式可以使用该key获取到值对象"}]}}',NULL,NULL,NULL,NULL),
	 ('14','14-异常节点','C','中断流程的执行并抛出异常','1','cn.zpaas.lowcode.be.engine.flow.node.ExceptionNode','{"节点配置参数":{"resultStatus":" 状态，可选值包括：400（非法请求）、500（内部错误）、900:（业务错误）","message":"详细异常信息；"}}',NULL,NULL,NULL,NULL),
	 ('15','03-动态属性取值','B','从一个对象中获取某个属性的值，输入一个对象，输出为获取到的值','1','cn.zpaas.lowcode.be.engine.flow.node.DynamicGetterNode','{"节点配置参数":{"fromObjectSource":"取值源对象获取来源，可选值包括：I、P、D、N，不可空","fromObjectKey":"取值源对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","fromObjectAttrSource":"取值源对象获取属性获取来源，业务逻辑流程节点中数据获取方式说明，可空","fromObjectAttrKey":"取值源对象获取属性获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","fromObjectAttrAttr":"取值源对象获取属性的获取属性，业务逻辑流程节点中数据获取方式说明，可空","isListType":"复制参数源对象是否列表，true、false，可空"}}',NULL,NULL,NULL,NULL),
	 ('16','38-ElasticSearch查询','S','从ElasticSearch中查询数据','1','cn.zpaas.lowcode.be.engine.flow.node.ESQueryNode','{"节点配置参数":{"sql":"要执行的sql","resourceId":" ES服务器标识","pageFlag":"是否支持分页，true、false"}}',NULL,NULL,NULL,NULL),
	 ('17','35-FTP/SFTP存取','S','从FTP/SFTP中存取文件','1','cn.zpaas.lowcode.be.engine.flow.node.FtpRepositoryNode','{"节点配置参数":{"ftpType":"ftp类型，包括ftp和sftp","ftpResourceId":"ftp资源标识","ftpOperation":"ftp操作，包括U：上传；D：下载；R：删除。当ftp操作类型为（U：上传）时，源文件名为业务流上下文中过程文件Map的Key，目标文件名为ftp、sftp服务器端的文件路径；当为（D：下载）时，源文件为ftp、sftp服务器端的文件路径，目标文件名无效；当为（R：删除）时，源文件为ftp、sftp服务器端的文件路径，目标文件名无效。","srcFileSource":"源文件的获取来源，包括P、U","srcFileNameSource":"源文件名的获取来源，可选值包括：I、P、D、N、F","srcFileNameKey":"源文件名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","srcFileNameAttr":"源文件名的获取属性，参见业务逻辑流程节点中数据获取方式说明","srcFileIsList":"源文件是否是列表类型，true、false","dstFileNameSource":"目标文件名的来源，可选值包括：I、P、D、N、F","dstFileNameKey":"目标文件名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","dstFileNameAttr":"目标文件名的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('18','51-Excel文件导入','F','导入Excel文件中的数据','1','cn.zpaas.lowcode.be.engine.flow.node.ExcelImportNode','{"节点配置参数":{"excelFileSource":"excel文件的获取来源，可选值包括：P、U","excelFileNameSource":"excel文件名的获取来源，可选值包括：I、P、D、N、F","excelFileNameKey":"excel文件名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","excelFileNameAttr":"excel文件名的获取属性，参见业务逻辑流程节点中数据获取方式说明","sheetIndex":"待处理的sheet页号，从0开始","processMode":"处理模式，可选值包括：F（流式处理）、B（批量处理）","startRowIndex":"开始处理的行数，从0开始，主要用于忽略表头对应的行","columnMappings":[{"columnIndex":"excel列序号","mappingName":"映射属性名"}],"subBusinessFlow":"流式处理子业务流流程，同样由各类流程节点组成的列表"}}',NULL,NULL,NULL,NULL);
INSERT INTO zpaas_lowcode_revise.be_flow_node (id,name,`type`,description,status,node_class,cfg_requirement,tenant_id,system_id,create_time,update_time) VALUES
	 ('19','52-Excel文件导出','F','将数据导出成excel文件','1','cn.zpaas.lowcode.be.engine.flow.node.ExcelExportNode','{"节点配置参数":{"exportDataSource":"导出数据的获取来源，可选值包括：I、P、D、N","exportDataKey":"导出数据的获取关键字，参见业务逻辑流程节点中数据获取方式说明","exportDataAttr":"导出数据的获取属性，参见业务逻辑流程节点中数据获取方式说明","isReOrder":"是否重排序，true、false，如果为true的情况下对来源数据按合并的列（needMerge==true, isSum==false,按列序号的顺序）进行重排序","exportHeader":"是否导出表头，true、false，默认为false","fileName":"导出文件名，为空时默认使用untitled.xlsx","excelTemplateSource":"excel文件模板的获取来源，在exportHeader为false的时候使用，可选值包括：I、P","excelTemplateKey":"excel文件模板的获取关键字，参见业务逻辑流程节点中数据获取方式说明","sheetIndex":"待导出的sheet页号，从0开始","startRowIndex":"开始插入的行号（sheet中的行号，从0开始）","columnMappings":[{"columnIndex":"excel列序号，从0开始","mappingName":"映射属性名","headerName":"表头的名字","needMerge":"是否需要合并，对于不累加的列，按列合并值相同的临近行；对于累加的列，相对累加维度列进行当前列值累加，如果设置了累加列，则对累加列值进行累加","isSum":"是否累加","sumByColumnIndex":"累加维度列，当需要累加的的情况下，如果未指定维度列，则表示累加所有行","sumColumnIndex":"累加列"}]}}',NULL,NULL,NULL,NULL),
	 ('2','02-参数转换','B','将一个对象的数据复制到另一个对象中，输入包括源对象和目标对象，输出完成复制的目标对象','1','cn.zpaas.lowcode.be.engine.flow.node.TransferNode','{"节点配置参数":{"fromObjectInstanceSource":"复制参数源对象获取来源，可选值包括：I、P、D、N、F，不可空","fromObjectInstanceKey":"复制参数源对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","fromObjectInstanceAttr":"复制参数源对象获取属性，业务逻辑流程节点中数据获取方式说明，可空","isListType":"复制参数源对象是否列表，true、false，可空","fromObjectType":"复制参数源对象的类型，可选值包括：D、V，不可空","fromObjectClass":"复制参数源对象的类，对应领域对象或值传递对象的标识，不可空","toObjectInstanceSource":"复制参数目标对象获取来源，可选值包括：P、D，不可空","toObjectInstanceKey":"复制参数目标对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","dataMappingId":"数据映射标识，包括参数复制的映射规则，不可空"}}',NULL,NULL,NULL,NULL),
	 ('20','61-流程操作','P','操作工作流引擎的流程实例','1','cn.zpaas.lowcode.be.engine.flow.node.WorkflowProcessOperatorNode','{"节点配置参数":{"processResourceId":"流程资源标识，选择方式，从工作流流程资源表中提取当前业务系统且状态为已部署的流程资源，再获取流程定义标识。启动时必填，其他情况下可空","processInstIdSource":"流程实例标识的获取来源，可选值包括：P、D、O、I、F。启动时可空，其他情况下必填","processInstIdKey":"流程实例标识的获取关键字，参见业务逻辑流程节点中数据获取方式说明","processInstIdAttr":"流程实例标识的获取属性，参见业务逻辑流程节点中数据获取方式说明","processOperation":"流程操作，可选值包括：S（启动）、R（重启）、D（删除）、P（挂起）、A（激活）","processVariablesSource":"流程参数的获取来源，可选值包括：I、P、N","processVariablesKey":"流程参数的获取关键字，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('21','63-流程任务查询','P','查询工作流引擎的待办流程任务','1','cn.zpaas.lowcode.be.engine.flow.node.WorkflowTaskQueryNode','{"节点配置参数":{"processDefIdSource":"流程定义标识的获取来源，可选值包括：P、D、O、I、F，可空。","processDefIdKey":"流程定义标识的获取关键字，参见业务逻辑流程节点中数据获取方式说明。可空。","processDefIdAttr":"流程定义标识的获取属性，参见业务逻辑流程节点中数据获取方式说明","processDefKeySource":"流程定义关键字的获取来源，可选值包括：P、D、O、I、F，可空。","processDefKeyKey":"流程定义关键字的获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空。","processDefKeyAttr":"流程定义关键字的获取属性，参见业务逻辑流程节点中数据获取方式说明","candidateGroupsSource":"任务候选组的获取来源，可选值包括：P、D、O、I、F，可空。","candidateGroupsKey":"任务候选组的获取关键字，参见业务逻辑流程节点中数据获取方式说明","assigneeSource":"任务绑定员工的获取来源，可选值包括：P、D、O、I、F，可空。","assigneeKey":"任务绑定员工的获取关键字，参见业务逻辑流程节点中数据获取方式说明。可空。","assigneeAttr":"任务绑定员工的获取属性，参见业务逻辑流程节点中数据获取方式说明","taskDefKeySource":"任务定义关键字的获取来源，可选值包括：P、D、O、I、F，可空。","taskDefKeyKey":"任务定义关键字的获取关键字，参见业务逻辑流程节点中数据获取方式说明。可空。","taskDefKeyAttr":"任务定义关键字的获取属性，参见业务逻辑流程节点中数据获取方式说明","processInstIdSource":"流程实例标识的获取来源，可选值包括：P、D、O、I、F，可空。","processInstIdKey":"流程实例标识的获取关键字，参见业务逻辑流程节点中数据获取方式说明。可空。","processInstIdAttr":"流程实例标识的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('22','62-流程任务操作','P','操作工作流引擎的流程任务','1','cn.zpaas.lowcode.be.engine.flow.node.WorkflowTaskOperatorNode','{"节点配置参数":{"taskIdSource":"任务实例标识获取来源，可选值包括：P、D、O、I、F，必填","taskIdKey":"任务实例标识的获取关键字，参见业务逻辑流程节点中数据获取方式说明","taskIdAttr":"任务实例标识的获取属性，参见业务逻辑流程节点中数据获取方式说明","taskOperation":"任务操作，可选值包括：A（领取）、C（完成）、G（委托）、D（删除）、R（解决）。必填。","processVariablesSource":"流程参数的获取来源，可选值包括：I、P、N。当任务操作为C和R时，表示要增加的流程参数；当为A和G时，表示用户标识；当是D时，表示删除原因。","processVariablesKey":"流程参数的获取关键字，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('23','90-哈希能力','T','调用哈希能力进行哈希/验证操作','1','cn.zpaas.lowcode.be.engine.flow.node.HashUtilsNode','{"节点配置参数":{"hashType":"Hash算法类型，包括M（MD5）、S（SHA256）、B（BCrypt）以及G（SM3）","operateType":"操作类型，包括E（加密）、V（验证）","rawStringSource":"明文的获取来源，可选值包括：I、P、D、N、F","rawStringKey":"明文的获取关键字，参见业务逻辑流程节点中数据获取方式说明","rawStringAttr":"明文的获取关键属性，参见业务逻辑流程节点中数据获取方式说明","encodedStringSource":"密文的获取来源，当进行V（验证）操作时有效，可选值包括：I、P、D、N、F","encodedStringKey":"密文的获取关键字，参见业务逻辑流程节点中数据获取方式说明","encodedStringAttr":"密文的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('24','34-Redis存取','S','从Redis中存取数据，输出获取到的缓存数据','1','cn.zpaas.lowcode.be.engine.flow.node.RedisRepositoryNode','{"节点配置参数":{"redisCommand":"要执行的redis命令，如set、get、ladd、keys...，以下命令不允许执行：auth,quit,flushdb,flushall,select,save,bgsave,shundown,info,monitor,slaveof,config","redisResourceId":"要操作的redis技术服务资源标识，从类型为redis的技术服务资源中选择","useObjectSerializer":"是否对返回结果使用对象序列器，true、false","params":[{"paramSource":"参数对象的获取来源，可选值包括：P、D、I、N、O、F","paramIsList":"参数对象是否是列表，true、false；","paramKey":"参数对象的获取关键字，参见业务逻辑流程节点中数据获取方式说明","paramAttrPath":"参数对象的获取属性，参见业务逻辑流程节点中数据获取方式说明"}]}}',NULL,NULL,NULL,NULL),
	 ('25','33-本地缓存','S','从本地缓存中存取数据，输出获取到的缓存数据','1','cn.zpaas.lowcode.be.engine.flow.node.LocalCacheNode','{"节点配置参数":{"cacheOperation":"缓存操作类型，包括G（get）、P（put）","cacheKeySource":"缓存Key的获取来源，可选值包括：I、P、D、N、F","cacheKeyKey":"缓存Key的获取关键字，参见业务逻辑流程节点中数据获取方式说明","cacheKeyAttr":"缓存Key的获取属性，参见业务逻辑流程节点中数据获取方式说明","cacheValueSource":"缓存值的获取来源，当进行P（put）操作时有效，可选值包括：I、P、D、N、F","cacheValueKey":"缓存值的获取关键字，参见业务逻辑流程节点中数据获取方式说明","cacheValueAttr":"缓存值的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('26','36-MinIO存取','S','从MinIO中存取文件','1','cn.zpaas.lowcode.be.engine.flow.node.MinioRepositoryNode','{"节点配置参数":{"minioResourceId":"minio资源标识","minioOperation":"minio操作，包括B：创建桶；U：上传；D：下载；R：删除文件；S：分享文件。当minio操作类型为（U：上传）时，源文件的来源、源文件名、桶、对象Key以及内容类型属性有效；当为（D：下载）时，桶以及对象Key属性有效；当为（B：创建桶）时，桶属性有效；当为（R：删除文件）时，桶以及对象Key属性有效；当为（S：分享文件）时，桶、对象Key以及有效期属性有效。","srcFileSource":"源文件的获取来源，包括P、U","srcFileNameSource":"源文件名的获取来源，可选值包括：I、P、D、N、F","srcFileNameKey":"源文件名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","srcFileNameAttr":"源文件名的获取属性，参见业务逻辑流程节点中数据获取方式说明","bucketSource":"桶的获取来源，可选值包括：I、P、D、N、F","bucketKey":"桶的获取关键字，参见业务逻辑流程节点中数据获取方式说明","bucketAttr":"桶的获取属性，参见业务逻辑流程节点中数据获取方式说明","objectKeySource":"对象Key的获取来源，可选值包括：I、P、D、N、F","objectKeyKey":"对象Key的获取关键字，参见业务逻辑流程节点中数据获取方式说明","objectKeyAttr":"对象Key的获取属性，参见业务逻辑流程节点中数据获取方式说明","contentTypeSource":"内容类型的获取来源，可选值包括：I、P、D、N、F","contentTypeKey":"内容类型的获取关键字，参见业务逻辑流程节点中数据获取方式说明","contentTypeAttr":"内容类型的获取属性，参见业务逻辑流程节点中数据获取方式说明","expireSource":"有效期的获取来源，可选值包括：I、P、D、N、F","expireKey":"有效期的获取关键字，参见业务逻辑流程节点中数据获取方式说明","expireAttr":"有效期的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('27','37-Kafka消息发送','S','发送Kafka消息','1','cn.zpaas.lowcode.be.engine.flow.node.KafkaMessageSendNode','{"节点配置参数":{"kafkaProducerId":"KafkaProducer资源标识","topicSource":"消息主题的获取来源，可选值包括：I、P、D、N、F","topicKey":"消息主题的获取关键字，参见业务逻辑流程节点中数据获取方式说明","topicAttr":"消息主题的获取属性，参见业务逻辑流程节点中数据获取方式说明","keySource":"消息key的获取来源，可选值包括：I、P、D、N、F","keyKey":"消息key的获取关键字，参见业务逻辑流程节点中数据获取方式说明","keyAttr":"消息key的获取属性，参见业务逻辑流程节点中数据获取方式说明","msgSource":"消息内容的获取来源，可选值包括：I、P、D、N、F","msgKey":"消息内容的获取关键字，参见业务逻辑流程节点中数据获取方式说明","msgAttr":"消息内容的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL);
INSERT INTO zpaas_lowcode_revise.be_flow_node (id,name,`type`,description,status,node_class,cfg_requirement,tenant_id,system_id,create_time,update_time) VALUES
	 ('28','53-JSON文件导入','F','导入JSON文件中的数据','1','cn.zpaas.lowcode.be.engine.flow.node.JSONImportNode','{"节点配置参数":{"jsonFileSource":"json文件的获取来源，可选值包括：P、U","jsonFileNameSource":"json文件名的获取来源，可选值包括：I、P、D、N、F","jsonFileNameKey":"json文件名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","jsonFileNameAttr":"json文件名的获取属性，参见业务逻辑流程节点中数据获取方式说明","processMode":"处理模式，可选值包括：F（流式处理）、B（批量处理）","startRowIndex":"开始处理的行数，从0开始，主要用于忽略表头对应的行","subBusinessFlow":"流式处理子业务流流程，同样由各类流程节点组成的列表"}}',NULL,NULL,NULL,NULL),
	 ('29','54-JSON文件导出','F','将数据导出成JSON文件','1','cn.zpaas.lowcode.be.engine.flow.node.JSONExportNode','{"节点配置参数":{"exportDataSource":"导出数据的获取来源，可选值包括：I、P、D、N","exportDataKey":"导出数据的获取关键字，参见业务逻辑流程节点中数据获取方式说明","exportDataAttr":"导出数据的获取属性，参见业务逻辑流程节点中数据获取方式说明","fileName":"导出文件名，为空时默认使用untitled.xlsx"}}',NULL,NULL,NULL,NULL),
	 ('3','20-本地方法调用','I','调用通过低代码平台编排的本地方法，输出方法执行后的返回结果','1','cn.zpaas.lowcode.be.engine.flow.node.LocalInvokeNode','{"节点配置参数":{"objectType":"调用对象类型，可选值包括：S（服务对象）、D（领域对象）","objectId":"调用对象标识，对应服务对象或领域对象的id","instanceKey":"调用对象实例获取关键字，只针对领域对象方法调用有效,参见业务逻辑流程节点中数据获取方式说明","operationId":"调用方法标识","asyncInvoke": "异步调用标志，包括true、false，默认为false","inParamInstanceSource":"参数实例获取来源，可选值包括：I、P、N","inParamInstanceKey":"参数实例获取关键字,参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('30','55-Text文件导入','F','导入文本文件中的数据','1','cn.zpaas.lowcode.be.engine.flow.node.TextImportNode','{"节点配置参数":{"txtFileSource":"txt文件的获取来源，包括P、U","txtFileNameSource":"txt文件名的获取来源，可选值包括：I、P、D、N、F","txtFileNameKey":"txt文件名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","txtFileNameAttr":"txt文件名是的获取属性，参见业务逻辑流程节点中数据获取方式说明","processMode":"处理模式，F：流式处理；B：批量处理","splitSymbol":"分隔符，用于分隔不同的列的值","startRowIndex":"开始处理的行数，从0开始，主要用于忽略表头对应的行","columnMappings":[{"columnIndex":"txt列序号","mappingName":"映射属性名"}],"subBusinessFlow":"流式处理子业务流流程，同样由各类流程节点组成的列表"}}',NULL,NULL,NULL,NULL),
	 ('31','56-Text文件导出','F','将数据导出成文本文件','1','cn.zpaas.lowcode.be.engine.flow.node.TextExportNode','{"节点配置参数":{"exportDataSource":"导出数据的获取来源，可选值包括：I、P、D、N","exportDataKey":"导出数据的获取关键字，参见业务逻辑流程节点中数据获取方式说明","exportDataAttr":"导出数据的获取属性，参见业务逻辑流程节点中数据获取方式说明","exportHeader":"是否导出表头，true、false，默认为false","fileName":"导出文件名，为空时默认使用untitled.txt","splitSymbol":"分隔符，用于分隔不同的列的值","columnMappings":[{"columnIndex":"列序号","mappingName":"映射属性名","headerName":"表头的名字"}]}}',NULL,NULL,NULL,NULL),
	 ('32','39-邮件发送','S','可用来发送Email邮件','1','cn.zpaas.lowcode.be.engine.flow.node.MailSendNode','{"节点配置参数":{"smtpResourceId":"smtp资源标识","fromSource":"发件人的获取来源，可选值包括：I、P、D、N、F","fromKey":"发件人的获取关键字，参见业务逻辑流程节点中数据获取方式说明","fromAttr":"发件人的获取属性，参见业务逻辑流程节点中数据获取方式说明","toSource":"收件人的获取来源，可选值包括：I、P、D、N、F","toKey":"收件人的获取关键字，参见业务逻辑流程节点中数据获取方式说明","toAttr":"收件人的获取属性，参见业务逻辑流程节点中数据获取方式说明","ccSource":"抄送人的获取来源，可选值包括：I、P、D、N、F","ccKey":"抄送人的获取关键字，参见业务逻辑流程节点中数据获取方式说明","ccAttr":"抄送人的获取属性，参见业务逻辑流程节点中数据获取方式说明","bccSource":"密送人的获取来源，可选值包括：I、P、D、N、F","bccKey":"密送人的获取关键字，参见业务逻辑流程节点中数据获取方式说明","bccAttr":"密送人的获取属性，参见业务逻辑流程节点中数据获取方式说明","subjectSource":"邮件主题的获取来源，可选值包括：I、P、D、N、F","subjectKey":"邮件主题的获取关键字，参见业务逻辑流程节点中数据获取方式说明","subjectAttr":"邮件主题的获取属性，参见业务逻辑流程节点中数据获取方式说明","contentSource":"邮件内容的获取来源，可选值包括：I、P、D、N、F","contentKey":"邮件内容的获取关键字，参见业务逻辑流程节点中数据获取方式说明","contentAttr":"邮件内容的获取属性，参见业务逻辑流程节点中数据获取方式说明","contentType":"内容类型，可选值包括：H（HTML类型）；P（文本类型）；","contentParams":[{"paramId":"参数序号，数字类型，与邮件中${1}、${2}、......、${n}占位符对应。邮件发送时使用具体的值替换对应的占位符。","paramSource":"参数值的获取来源，可选值包括：I、P、D、N、F","paramKey":"参数值的获取关键字，参见业务逻辑流程节点中数据获取方式说明","paramAttr":"参数值的获取属性，参见业务逻辑流程节点中数据获取方式说明"}],"attachments":[{"attachmentName":"附件名","attachmentType":"附件类型","attachmentId":"附件标识","attachmentFileSource":"文件的获取来源，可选值包括：P、U","attachmentFileNameSource":"文件名的获取来源，可选值包括：I、P、D、N、F","attachmentFileNameKey":"文件名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","attachmentFileNameAttr":"文件名的获取属性，参见业务逻辑流程节点中数据获取方式说明"}]}}',NULL,NULL,NULL,NULL),
	 ('33','40-短信发送','S','可用来发送短信','1','cn.zpaas.lowcode.be.engine.flow.node.SmsSendNode','{"节点配置参数":{"smsGatewayId":"短信网关资源标识","receiverSource":"收信人的获取来源，可选值包括：I、P、D、N、F。当多个收集人时，使用逗号分隔。","receiverKey":"收信人的获取关键字，参见业务逻辑流程节点中数据获取方式说明","receiverAttr":"收信人的获取属性，参见业务逻辑流程节点中数据获取方式说明","contentSource":"短信内容的获取来源，可选值包括：I、P、D、N、F","contentKey":"短信内容的获取关键字，参见业务逻辑流程节点中数据获取方式说明","contentAttr":"短信内容的获取属性，参见业务逻辑流程节点中数据获取方式说明","contentParams":[{"paramId":"参数序号，数字类型，与邮件中${1}、${2}、......、${n}占位符对应。短信发送时使用具体的值替换对应的占位符。","paramSource":"参数值的获取来源，可选值包括：I、P、D、N、F","paramKey":"参数值的获取关键字，参见业务逻辑流程节点中数据获取方式说明","paramAttr":"参数值的获取属性，参见业务逻辑流程节点中数据获取方式说明"}]}}',NULL,NULL,NULL,NULL),
	 ('34','06-类型转换','B','支持变量类型的转换，输入一个源变量，输出转换类型后的变量','1','cn.zpaas.lowcode.be.engine.flow.node.TypeConvertNode','{"节点配置参数":{"toType":"目标对象的类型，可选值包括：S（String），J（JSON对象）","fromObjectInstanceSource":"类型转换源对象获取来源，可选值包括：I、P、D、N、F，不可空","fromObjectInstanceKey":"类型转换源对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","fromObjectInstanceAttr":"类型转换源对象获取属性，业务逻辑流程节点中数据获取方式说明，可空"}}
INSERT INTO zpaas_lowcode_revise.be_flow_node (id,name,`type`,description,status,node_class,cfg_requirement,tenant_id,system_id,create_time,update_time) VALUES
	 ('37','71-动态参数转换','D','根据某个参数的值，加载不同的参数复制规则进行对象属性的复制','1','cn.zpaas.lowcode.be.engine.flow.node.DynamicTransferNode','{"节点配置参数":{"isListType":"源对象实例是否列表类型，true、false","fromObjectInstanceSource":"源对象实例的获取来源，可选值包括：I、P、D、N","fromObjectInstanceKey":"源对象实例的获取关键字，参见业务逻辑流程节点中数据获取方式说明","fromObjectInstanceAttr":"源对象实例的获取属性，参见业务逻辑流程节点中数据获取方式说明","toObjectInstanceSource":"目标对象实例的获取来源，可空，如果目标对象实例已经存在的情况下配置，这种情况下，后置配置信息中的相关信息可以不用配置，可选值包括：P、D","toObjectInstanceKey":"目标对象实例的获取关键字，参见业务逻辑流程节点中数据获取方式说明","dynamicMappingId":"动态映射标识，选择映射类型为D（数据映射）的动态映射数据。","keyValueSource":"动态关键值的获取来源，可选值包括：I、P、D、N","keyValueKey":"动态关键值的获取关键字，参见业务逻辑流程节点中数据获取方式说明","keyValueAttr":"动态关键值的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('38','73-动态本地方法调用','D','根据某个参数的值，动态调用通过低代码平台编排的本地方法','1','cn.zpaas.lowcode.be.engine.flow.node.DynamicLocalInvokeNode','{"节点配置参数":{"dynamicMappingId":"动态映射标识，选择映射类型为D（数据映射）的动态映射数据。","keyValueSource":"动态关键值的获取来源，可选值包括：I、P、D、N","keyValueKey":"动态关键值的获取关键字，参见业务逻辑流程节点中数据获取方式说明","keyValueAttr":"动态关键值的获取属性，参见业务逻辑流程节点中数据获取方式说明","asyncInvoke":"异步调用，包括true、false，默认为false","inParamInstanceSource":"参数实例的获取来源，可选值包括：I、P、N","inParamInstanceKey":"参数实例的获取关键字，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('39','91-ZIP能力','T','通过ZIP进行压缩/解压缩操作','1','cn.zpaas.lowcode.be.engine.flow.node.ZipUtilsNode','{"节点配置参数":{"zipOperation":"Zip操作，C：压缩；U：解压缩","fileName":"文件名，压缩操作时为目标压缩文件名，为空时默认使用untitled.zip；解压缩时为目标目录前缀，默认为unzip，同时也作为存到过程数据的key的前缀。","srcFiles":[{"srcFileSource":"源文件的获取来源，可选值包括：I、P、D、N","srcFileKey":"源文件的获取关键字，参见业务逻辑流程节点中数据获取方式说明","srcFileAttr":"源文件的获取属性，参见业务逻辑流程节点中数据获取方式说明"}]}}',NULL,NULL,NULL,NULL),
	 ('4','01-参数校验','B','对对象类型的参数进行合法性校验，输入一个对象，输出为校验结果','1','cn.zpaas.lowcode.be.engine.flow.node.ValidateNode','{"节点配置参数":{"targetObjectInstanceSource":"校验目标数据对象获取来源，可选值包括：I、P、D、N、F，不可空","targetObjectInstanceKey":"校验目标数据对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","targetObjectInstanceAttr":"校验目标数据对象获取属性，业务逻辑流程节点中数据获取方式说明，可空","isListType":"校验目标数据对象是否列表，true、false，可空","targetObjectType":"校验目标数据对象的类型，可选值包括：D、V，不可空","targetObjectClass":"校验目标数据对象的类，对应领域对象或值传递对象的标识，不可空","ruleGroupId":"校验规则，要执行的校验规则，不可空","interruptBusinessFlow":"当校验不通过时，是否中断业务流执行，true、false，不可空"}}',NULL,NULL,NULL,NULL),
	 ('40','30-字典缓存读取','S','支持读取字典缓存数据，输出获取到的字典数据','1','cn.zpaas.lowcode.be.engine.flow.node.DictRepositoryNode','{"节点配置参数":{"dictResourceId":"要读取字典的资源标识","dictCodeSource":"字典编码的获取来源，可选值包括：I、P、D、N、F","dictCodeKey":"字典编码的获取关键字，参见业务逻辑流程节点中数据获取方式说明","dictCodeAttr":"字典编码获取属性，参见业务逻辑流程节点中数据获取方式说明","dictValueSource":"字典值的获取来源，可选值包括：I、P、D、N、F","dictValueKey":"字典值的获取关键字，参见业务逻辑流程节点中数据获取方式说明","dictValueAttr":"字典值获取属性，参见业务逻辑流程节点中数据获取方式说明","parentDictCodeSource":"上级字典编码的获取来源，可选值包括：I、P、D、N、F","parentDictCodeKey":"上级字典编码的获取关键字，参见业务逻辑流程节点中数据获取方式说明","parentDictCodeAttr":"上级字典编码的获取属性，参见业务逻辑流程节点中数据获取方式说明","parentDictValueSource":"上级字典值的获取来源，可选值包括：I、P、D、N、F","parentDictValueKey":"上级字典值的获取关键字，参见业务逻辑流程节点中数据获取方式说明","parentDictValueAttr":"上级字典值的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('41','50-本地文件操作','F','可用来操作本地文件系统中的文件','1','cn.zpaas.lowcode.be.engine.flow.node.LocalFileNode','{"节点配置参数":{"fileType":"文件类型，可选值包括：F（文件）、D（目录）","fileOperation":"执行操作，可选值包括：C：创建；D：删除；R：重命名；M：移动（只对文件有效）；P：复制（只对文件有效）；W：写入（只对文件有效）；F：判断是否是文件；E：判断是否存在；L：查看文件列表（只对目录有效）；G：获取文件","localFileSource":"本地文件的获取来源，可选值包括：I、P、D、N、U","localFileKey":"本地文件的获取关键字，参见业务逻辑流程节点中数据获取方式说明","localFileAttr":"本地文件的获取属性","destFileSource":"目标文件的获取来源，可选值包括：I、P、D、N","destFileKey":"目标文件的获取关键字，参见业务逻辑流程节点中数据获取方式说明","destFileAttr":"目标文件的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('42','92-加解密能力','T','可用来进行加密/解密操作','1','cn.zpaas.lowcode.be.engine.flow.node.CipherUtilsNode','{"节点配置参数":{"cipherAlgorithmType":"算法类型，包括DES、DESede、AES、SM4、RSA、SM2","cipherAlgorithm":"算法，包括DES、ECB、PKCS5Padding、DES、ECB、NoPadding、DES、CBC、PKCS5Padding、DES、CBC、NoPadding、DESede、ECB、PKCS5Padding、DESede、ECB、NoPadding、DESede、CBC、PKCS5Padding、DESede、CBC、NoPadding、AES、ECB、PKCS5Padding、AES、ECB、NoPadding、AES、CBC、PKCS5Padding、AES、CBC、NoPadding、SM4、ECB、PKCS5Padding、SM4、ECB、NoPadding、SM4、CBC、PKCS5Padding、SM4、CBC、NoPadding、RSA、ECB、PKCS1Padding、SM2","securityKeyResourceId":"安全密钥资源标识，根据算法从安全密钥资源表中加载对应的安全密钥资源。","operationType":"操作类型，包括E：加密，D：解密。","srcTextSource":"源文本的获取来源，可选值包括：I、P、D、N、F","srcTextKey":"源文本的获取关键字，参见业务逻辑流程节点中数据获取方式说明","srcTextAttr":"源文本的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('43','93-签名验签能力','T','可用来进行签名/验签操作','1','cn.zpaas.lowcode.be.engine.flow.node.SignatureUtilsNode','{"节点配置参数":{"cipherAlgorithmType":"算法类型，包括RSA、SM2","cipherAlgorithm":"算法，包括SHA256withRSA、SHA1withRSA、MD5withRSA、1.2.156.10197.1.501","securityKeyResourceId":"安全密钥资源标识，根据算法从安全密钥资源表中加载对应的安全密钥资源。","operationType":"操作类型，包括S：签名，V：验签。","srcTextSource":"源文本的获取来源，可选值包括：I、P、D、N、F","srcTextKey":"源文本的获取关键字，参见业务逻辑流程节点中数据获取方式说明","srcTextAttr":"源文本的获取属性，参见业务逻辑流程节点中数据获取方式说明","signTextSource":"签名文本的获取来源，可选值包括：I、P、D、N、F、","signTextKey":"签名文本的获取关键字，参见业务逻辑流程节点中数据获取方式说明","signTextAttr":"签名文本的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('44','80-AIGC能力调用','A','可用来调用AIGC能力','1','cn.zpaas.lowcode.be.engine.flow.node.AigcInvokeNode','{"节点配置参数":{"aigcResourceId":"aigc服务，从ServerResource中加载类型为A：aigc服务的资源。","model":"调用模型","invokeApi":"调用API类型，包括、api、generate,、api、chat","isStream":是"否流式，包括Y：是；N：否","options":"模型参数，如：{temperature:0.7,max_tokens:100}","messageSource":"消息的获取来源，可选值包括：I、P、D、N、F","messageKey":"消息的获取关键字，参见业务逻辑流程节点中数据获取方式说明","messageAttr":"消息的获取属性，参见业务逻辑流程节点中数据获取方式说明","historySource":"历史消息的获取来源，可选值包括：I、P、D、N、F。当调用API类型为、api、chat时有效。消息的格式为JsonArray类型，如下：[{''role'':''user'',''content'':''<input-text>''},{''role'':''assistant'',''content'':''<generated-text>''}]","historyKey":"历史消息的获取关键字，参见业务逻辑流程节点中数据获取方式说明","historyAttr":"历史消息的获取属性，参见业务逻辑流程节点中数据获取方式说明","userNameSource":"用户名的获取来源，可选值包括：I、P、D、N、F。当调用API类型为、api、chat时有效。","userNameKey":"用户名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","userNameAttr":"用户名的获取属性，参见业务逻辑流程节点中数据获取方式说明","assistantNameSource":"助手名的获取来源，可选值包括：I、P、D、N、F。当调用API类型为、api、chat时有效。","assistantNameKey":"助手名的获取关键字，参见业务逻辑流程节点中数据获取方式说明","assistantNameAttr":"助手名的获取属性，参见业务逻辑流程节点中数据获取方式说明"}}',NULL,NULL,NULL,NULL),
	 ('5','04-对象属性设置','B','设置对象的属性值，支持创建对象并初始化设置属性值，输出设置好的对象，该对象可以是新增的，也可以已存在的对象','1','cn.zpaas.lowcode.be.engine.flow.node.ObjectSetterNode','{"节点配置参数":{"toObjectInstanceSource":"属性设置目标对象获取来源，可选值包括：I、P、D、N、F、O，当需要新建对象时，该属性为空","toObjectInstanceKey":"属性设置目标对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","toObjectInstanceAttr":"属性设置目标对象获取属性，业务逻辑流程节点中数据获取方式说明，可空","isListType":"复制参数源对象是否列表，true、false，可空","toObjectType":"属性设置目标对象的类型，可选值包括：D、V、J，不可空","toObjectClass":"属性设置目标对象的类，对应领域对象、值传递对象的标识或者全路径的JDK原生对象，不可空","paramRules":[{"fromObjectIsList":"源对象是否是列表类型，true、false","fromObjectType":"源对象获取类型，可选值包括：I、P、D、F，不可空","fromObjectKey":"源对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，不可空","attrMappings":[{"fromAttrPath":"源对象属性对应的json path，如果是“/”，则表示源对象本身","toObjectAttr":"目标参数的属性名，也需要支持json path格式"}]}]}}',NULL,NULL,NULL,NULL);
INSERT INTO zpaas_lowcode_revise.be_flow_node (id,name,`type`,description,status,node_class,cfg_requirement,tenant_id,system_id,create_time,update_time) VALUES
	 ('6','12-条件分支节点','C','提供条件判断分支的能力，分支中的逻辑包含在子流程中','1','cn.zpaas.lowcode.be.engine.flow.node.ConditionNode','{"节点配置参数":{"conditionExpr":"条件表达式，如（${1} and ${2}）or (${3} and ${4} and ${5})，其中的数字表示conditions列表中条件的顺序号，采用SpringEL表达式的格式，每个数字都会替换成一个boolean值。","conditions":[{"conditionObjectSource":"条件判断对象获取来源，可选值包括：P、D、I、N、O、F，不可空","conditionObjectIsList":"条件判断对象是否是列表，true、false；","conditionObjectKey":"条件判断对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","conditionAttrPath":"条件判断对象获取属性，参见业务逻辑流程节点中数据获取方式说明，可空","conditionOperator":"条件比较操作符，包括EQ（等于）、NE（不等于）、GT（大于）、GE（大于等于）、LT（小于）、LE（小于等于）","compareType":"条件值比较类型，包括B（boolean比较）、S（字符串比较）、D（日期比较）、N（数值比较）、C（数组的大小比较）、L（长度比较）、H（是否包含）、O（是否对象）、A（是否数组）","valueObjectSource":"条件判断值对象获取来源，可选值包括：P、D、I、N、O、F，不可空","valueObjectIsList":"条件判断值对象是否是列表，true、false；","valueObjectKey":"条件判断值对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","valueAttrPath":"条件判断值对象获取属性"}],"subBusinessFlow":"分支执行的子业务流流程，同样由各类流程节点组成的列表"}}',NULL,NULL,NULL,NULL),
	 ('7','31-Sql查询','S','支持在关系型数据库中执行SQL获取结果数据，输出SQL的执行结果','1','cn.zpaas.lowcode.be.engine.flow.node.SqlQueryNode','{"节点配置参数":{"sql":"要执行的SQL语句","pageFlag":"是否支持分页，true、false"}}',NULL,NULL,NULL,NULL),
	 ('8','11-循环节点','C','提供循环的能力，循环中的逻辑包含在子流程中，需要输入一个循环的对象列表','1','cn.zpaas.lowcode.be.engine.flow.node.ForEachNode','{"节点配置参数":{"arrayObjectSource":"循环列表对象获取来源，可选值包括：I、P、D、N、F、O，不可空","arrayObjectKey":"循环列表对象获取关键字，参见业务逻辑流程节点中数据获取方式说明，可空","arrayAttrPath":"循环列表对象获取属性，业务逻辑流程节点中数据获取方式说明，可空","arrayElementIsList":"循环列表的每个元素对象是否是列表，true、false","arrayElementObjectType":"循环列表元素对象的类型，可选值包括：D、V、J","arrayElementObjectClass":"循环列表元素对象的类，对应领域对象标识、值传递对象的标识或者全路径的Java类","subBusinessFlow":"循环分支执行的子业务流程，同样由各类流程节点组成的列表"}}',NULL,NULL,NULL,NULL),
	 ('9','13-中断节点','C','中断当前流程/子流程的执行','1','cn.zpaas.lowcode.be.engine.flow.node.BreakNode','{"节点配置参数":{"breakTimes":"中断循环的层次数，默认为1次"}}
